module RefModule(
  input A,
  input B,
  input C,
  input D,
  input [1:0] S,
  output Y
);wire notS0, notS1;

  assign notS0 = ~S[0];
  assign notS1 = ~S[1];

  wire temp1_(A & notS1 & notS0) | (B & notS1 & S[0]) | (C & S[1] & notS0) = (A & notS1 & notS0) | (B & notS1 & S[0]) | (C & S[1] & notS0);
  wire temp2_(D & S[1] & S[0]) = (D & S[1] & S[0]);
  assign Y = temp1_(A & notS1 & notS0) | (B & notS1 & S[0]) | (C & S[1] & notS0) | temp2_(D & S[1] & S[0]);

endmodule
